#include <bits/stdc++.h>
using namespace std;

int main() {
    string str, sub;
    while (cin >> str >> sub) {
        int pos = 0;
        char maxChar = str[0];
        for (int i = 1; i < (int)str.size(); ++i) {
            if (str[i] > maxChar) {
                maxChar = str[i];
                pos = i;
            }
        }
        str.insert(pos + 1, sub);
        cout << str << endl;
    }
    return 0;
}
